TRUNCATE TABLE product_category RESTART IDENTITY CASCADE;

-- Вставляем категории
INSERT INTO product_category
        (name,
        slug,
        description)
VALUES
    ('Процессоры', 'cpus', 'Центральные процессоры (CPU) для настольных ПК. Основные характеристики: сокет, количество ядер, тактовая частота, TDP, наличие встроенной графики.'),
    ('Материнские платы', 'motherboards', 'Материнские платы (Motherboard) — основа ПК. Определяют совместимость всех компонентов. Характеристики: сокет, чипсет, форм-фактор, тип поддерживаемой памяти, разъемы.'),
    ('Оперативная память', 'ram', 'Модули оперативной памяти (RAM, ОЗУ). Характеристики: тип (DDR4/DDR5), объем, частота, тайминги, форм-фактор (DIMM для ПК, SO-DIMM для ноутбуков).'),
    ('Видеокарты', 'gpus', 'Дискретные видеокарты (GPU) для игр и работы с графикой. Характеристики: производитель чипа (NVIDIA/AMD), объем видеопамяти, частота, TDP, необходимое питание, разъемы.'),
    ('Накопители', 'storage', 'SSD и HDD диски для хранения данных. Характеристики: тип (SSD/HDD), форм-фактор (2.5", 3.5", M.2), интерфейс (SATA, NVMe), объем, скорость чтения/записи.'),
    ('Блоки питания', 'psus', 'Блоки питания (PSU) обеспечивают энергией все компоненты. Характеристики: мощность, форм-фактор (ATX, SFX), сертификат эффективности (80+), модульность кабелей.'),
    ('Корпуса', 'cases', 'Компьютерные корпуса. Характеристики: форм-фактор поддерживаемых материнских плат (ATX, mATX, ITX), размеры, количество вентиляторов, поддержка жидкостного охлаждения.'),
    ('Кулеры для процессора', 'cpu_coolers', 'Системы охлаждения для процессоров: воздушные (башенные, мало профильные) и жидкостные (СЖО). Характеристики: поддерживаемые сокеты, TDP рассеивания, размер вентиляторов.'),
    ('Корпусные вентиляторы', 'case_fans', 'Вентиляторы для корпусов. Характеристики: размер (120mm, 140mm), скорость вращения, тип подшипника, уровень шума, подсветка.'),
    ('Термоинтерфейсы', 'thermal_paste', 'Термопасты и жидкий металл для улучшения теплопередачи между процессором и кулером.'),
    ('Звуковые карты', 'sound_cards', 'Дискретные звуковые карты для улучшенного звука. Характеристики: разрядность, частота дискретизации, интерфейс подключения, выходы.'),
    ('Сетевые адаптеры', 'network_cards', 'Сетевые карты и Wi-Fi адаптеры. Характеристики: интерфейс (PCIe, USB), стандарт Wi-Fi, скорость передачи данных.'),
    ('Контроллеры', 'controllers', 'Контроллеры расширения: USB, SATA, RAID и другие.'),
    ('Дисководы', 'optical_drives', 'Приводы для чтения/записи оптических дисков (DVD, Blu-ray). Характеристики: интерфейс, поддерживаемые форматы дисков.');